/**
 * Profile Component - Blockchain-Only Version
 * 
 * Displays user profile with rooms and NFTs fetched from the blockchain.
 * Uses getContractReadOnly() to fetch data safely with proper error handling.
 * All data comes from Sepolia blockchain - no mock data.
 */

import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { getContractReadOnly } from '../utils/contract';
import { useWallet } from '../contexts/WalletContext';
import MyNFTs from '../components/MyNFTs';
import ListNFT from '../components/ListNFT';
import MintNFT from '../components/MintNFT';
import {
  User,
  MessageSquare,
  Crown,
  Settings,
  Copy,
  ExternalLink,
  Loader,
  AlertCircle,
  Lock,
  Globe,
  Image as ImageIcon,
  Edit3,
  Save,
  X,
  Camera,
  QrCode,
  Scan,
  Plus
} from 'lucide-react';
import QRCodeModal from '../components/QRCode/QRCodeModal';
import QRScanner from '../components/QRCode/QRScanner';

const Profile = () => {
  const { walletAddress, userProfile, updateProfile } = useWallet();
  
  // State management - all initialized as empty arrays
  const [allRooms, setAllRooms] = useState([]);
  const [userCreatedRooms, setUserCreatedRooms] = useState([]);
  const [userJoinedRooms, setUserJoinedRooms] = useState([]);
  const [blockchainNFTs, setBlockchainNFTs] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [copied, setCopied] = useState(false);
  
  // UI state
  const [isEditing, setIsEditing] = useState(false);
  const [editForm, setEditForm] = useState(userProfile);
  const [showQRCode, setShowQRCode] = useState(false);
  const [showQRScanner, setShowQRScanner] = useState(false);
  const [showMintNFT, setShowMintNFT] = useState(false);
  const [showListNFT, setShowListNFT] = useState(false);
  const [selectedNFT, setSelectedNFT] = useState(null);
  const [activeTab, setActiveTab] = useState('rooms'); // 'rooms' or 'nfts'

  /**
   * Format wallet address to short version
   */
  const formatAddress = (address) => {
    if (!address) return '';
    return `${address.slice(0, 6)}...${address.slice(-4)}`;
  };

  /**
   * Format date from timestamp
   */
  const formatDate = (timestamp) => {
    try {
      const date = new Date(Number(timestamp) * 1000);
      return date.toLocaleDateString('en-US', {
        month: 'short',
        day: 'numeric',
        year: 'numeric'
      });
    } catch {
      return 'Unknown';
    }
  };

  /**
   * Copy wallet address to clipboard
   */
  const copyAddress = async () => {
    if (walletAddress) {
      try {
        await navigator.clipboard.writeText(walletAddress);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
      } catch (err) {
        console.error('Failed to copy address:', err);
      }
    }
  };

  /**
   * Handle profile editing
   */
  const handleEditProfile = () => {
    setEditForm(userProfile);
    setIsEditing(true);
  };

  const handleSaveProfile = () => {
    updateProfile(editForm);
    setIsEditing(false);
  };

  const handleCancelEdit = () => {
    setEditForm(userProfile);
    setIsEditing(false);
  };

  const handleInputChange = (field, value) => {
    setEditForm(prev => ({ ...prev, [field]: value }));
  };

  /**
   * Handle QR code friend request
   */
  const handleFriendRequest = (friendData) => {
    console.log('Friend request:', friendData);
    alert(`Friend request sent to ${friendData.displayName}!`);
  };

  /**
   * Fetch all rooms from blockchain and filter user-specific rooms
   */
  const fetchUserRooms = async () => {
    if (!walletAddress) {
      console.log('⚠️ No wallet address available');
      return;
    }

    try {
      console.log('📥 Fetching all rooms from blockchain for user:', walletAddress);

      const contract = await getContractReadOnly();
      const rooms = await contract.getAllRooms();
      
      console.log('📊 Raw rooms from blockchain:', rooms?.length || 0);

      // Transform rooms safely - handle BigInt conversion
      const transformedRooms = (rooms || []).map(room => ({
        id: Number(room?.id || 0),
        name: room?.name || 'Unnamed Room',
        creator: room?.creator || '',
        isPrivate: room?.isPrivate || false,
        createdAt: Number(room?.createdAt || 0),
        exists: room?.exists || false
      })).filter(room => room.exists);

      setAllRooms(transformedRooms);
      console.log('✅ All rooms processed:', transformedRooms.length);

      // Filter rooms created by user
      const createdRooms = transformedRooms.filter(room => 
        room?.creator?.toLowerCase() === walletAddress?.toLowerCase()
      );
      setUserCreatedRooms(createdRooms);
      console.log('👤 User created rooms:', createdRooms.length);

      // Filter other rooms (potentially joinable)
      const otherRooms = transformedRooms.filter(room => 
        room?.creator?.toLowerCase() !== walletAddress?.toLowerCase()
      );
      setUserJoinedRooms(otherRooms);
      console.log('🚪 Other rooms available:', otherRooms.length);

    } catch (err) {
      console.error('❌ Failed to fetch user rooms:', err);
      setError(err?.message || 'Failed to load rooms');
    }
  };

  /**
   * Fetch user's NFTs from blockchain
   */
  const fetchUserNFTs = async () => {
    if (!walletAddress) {
      console.log('⚠️ No wallet address for NFT fetch');
      return;
    }

    try {
      console.log('🖼️ Fetching NFTs for user:', walletAddress);

      const contract = await getContractReadOnly();
      
      // Check if contract has NFT functions
      if (typeof contract.getNFTsByOwner === 'function') {
        const nfts = await contract.getNFTsByOwner(walletAddress);
        
        console.log('📊 Raw NFTs from blockchain:', nfts?.length || 0);

        // Transform NFTs safely - handle BigInt conversion
        const transformedNFTs = (nfts || []).map(nft => ({
          tokenId: Number(nft?.tokenId || 0),
          name: nft?.name || 'Unnamed NFT',
          owner: nft?.owner || '',
          metadataURI: nft?.metadataURI || '',
          price: nft?.price?.toString() || '0',
          isListed: nft?.isListed || false
        }));

        setBlockchainNFTs(transformedNFTs);
        console.log('✅ User NFTs processed:', transformedNFTs.length);
      } else {
        console.log('ℹ️ Contract does not have getNFTsByOwner function');
        setBlockchainNFTs([]);
      }
    } catch (err) {
      console.warn('⚠️ Could not fetch NFTs:', err?.message);
      // Don't set error for NFTs, just use empty array
      setBlockchainNFTs([]);
    }
  };

  /**
   * Fetch all user data from blockchain
   */
  const fetchUserData = async () => {
    setLoading(true);
    setError(null);

    try {
      await Promise.all([
        fetchUserRooms(),
        fetchUserNFTs()
      ]);
    } catch (err) {
      console.error('❌ Failed to fetch user data:', err);
      setError(err?.message || 'Failed to load profile data');
    } finally {
      setLoading(false);
    }
  };

  /**
   * Fetch data on mount and when wallet changes
   */
  useEffect(() => {
    if (walletAddress) {
      fetchUserData();
    } else {
      setLoading(false);
    }
  }, [walletAddress]);

  /**
   * Update edit form when userProfile changes
   */
  useEffect(() => {
    setEditForm(userProfile);
  }, [userProfile]);

  /**
   * Not connected state
   */
  if (!walletAddress) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center max-w-md">
          <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <User className="w-8 h-8 text-gray-400" />
          </div>
          <h2 className="text-xl font-semibold text-gray-900 mb-2">Connect Your Wallet</h2>
          <p className="text-gray-600 mb-4">
            Please connect your wallet to view your profile and rooms.
          </p>
          <Link to="/" className="btn-primary">
            Connect Wallet
          </Link>
        </div>
      </div>
    );
  }

  /**
   * Loading state
   */
  if (loading) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center">
          <Loader className="w-8 h-8 text-primary-600 animate-spin mx-auto mb-4" />
          <p className="text-gray-600">Loading profile from blockchain...</p>
        </div>
      </div>
    );
  }

  /**
   * Error state
   */
  if (error) {
    return (
      <div className="flex items-center justify-center h-full">
        <div className="text-center max-w-md">
          <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
            <AlertCircle className="w-8 h-8 text-red-600" />
          </div>
          <h2 className="text-xl font-semibold text-gray-900 mb-2">Failed to Load Profile</h2>
          <p className="text-gray-600 mb-4">{error}</p>
          <button onClick={fetchUserData} className="btn-primary">
            Try Again
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Profile Header */}
      <div className="card">
        <div className="flex items-start space-x-6">
          <div className="relative">
            {userProfile?.avatar ? (
              <img 
                src={userProfile.avatar} 
                alt="Profile" 
                className="w-20 h-20 rounded-full object-cover"
              />
            ) : (
              <div className="w-20 h-20 bg-gradient-to-br from-primary-400 to-purple-500 rounded-full flex items-center justify-center">
                <User className="w-10 h-10 text-white" />
              </div>
            )}
            {isEditing && (
              <button className="absolute -bottom-1 -right-1 w-6 h-6 bg-primary-600 rounded-full flex items-center justify-center text-white hover:bg-primary-700">
                <Camera className="w-3 h-3" />
              </button>
            )}
          </div>
          <div className="flex-1">
            <div className="flex items-center space-x-3 mb-2">
              <h1 className="text-2xl font-bold text-gray-900">
                {userProfile?.displayName || formatAddress(walletAddress)}
              </h1>
              <button
                onClick={copyAddress}
                className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                title="Copy address"
              >
                <Copy className="w-4 h-4" />
              </button>
              {copied && (
                <span className="text-sm text-green-600 font-medium">Copied!</span>
              )}
            </div>
            <p className="text-gray-600 mb-2">
              {userProfile?.bio || 'Manage your DeChat account'}
            </p>
            <div className="flex items-center space-x-4 text-sm text-gray-600">
              <span>Connected to Sepolia</span>
              <span>•</span>
              <a
                href={`https://sepolia.etherscan.io/address/${walletAddress}`}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center space-x-1 text-primary-600 hover:text-primary-700"
              >
                <span>View on Etherscan</span>
                <ExternalLink className="w-3 h-3" />
              </a>
            </div>
          </div>
          <div className="flex space-x-2">
            {isEditing ? (
              <>
                <button
                  onClick={handleSaveProfile}
                  className="btn-primary flex items-center space-x-2"
                >
                  <Save className="w-4 h-4" />
                  <span>Save</span>
                </button>
                <button
                  onClick={handleCancelEdit}
                  className="btn-secondary flex items-center space-x-2"
                >
                  <X className="w-4 h-4" />
                  <span>Cancel</span>
                </button>
              </>
            ) : (
              <>
                <button
                  onClick={() => setShowQRScanner(true)}
                  className="btn-secondary flex items-center space-x-2"
                >
                  <Scan className="w-4 h-4" />
                  <span>Scan QR</span>
                </button>
                <button
                  onClick={() => setShowQRCode(true)}
                  className="btn-secondary flex items-center space-x-2"
                >
                  <QrCode className="w-4 h-4" />
                  <span>My QR</span>
                </button>
                <button
                  onClick={handleEditProfile}
                  className="btn-primary flex items-center space-x-2"
                >
                  <Edit3 className="w-4 h-4" />
                  <span>Edit</span>
                </button>
              </>
            )}
          </div>
        </div>
      </div>

      {/* Profile Edit Form */}
      {isEditing && (
        <div className="card">
          <h2 className="text-lg font-semibold text-gray-900 mb-4">Edit Profile</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Display Name
              </label>
              <input
                type="text"
                value={editForm?.displayName || ''}
                onChange={(e) => handleInputChange('displayName', e.target.value)}
                placeholder="Your display name"
                className="input-field"
              />
            </div>
            
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Location
              </label>
              <input
                type="text"
                value={editForm?.location || ''}
                onChange={(e) => handleInputChange('location', e.target.value)}
                placeholder="Your location"
                className="input-field"
              />
            </div>
            
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Bio
              </label>
              <textarea
                value={editForm?.bio || ''}
                onChange={(e) => handleInputChange('bio', e.target.value)}
                placeholder="Tell us about yourself..."
                rows={3}
                className="input-field resize-none"
              />
            </div>
            
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Website
              </label>
              <input
                type="url"
                value={editForm?.website || ''}
                onChange={(e) => handleInputChange('website', e.target.value)}
                placeholder="https://yourwebsite.com"
                className="input-field"
              />
            </div>
            
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Twitter
              </label>
              <input
                type="text"
                value={editForm?.twitter || ''}
                onChange={(e) => handleInputChange('twitter', e.target.value)}
                placeholder="@yourusername"
                className="input-field"
              />
            </div>
            
            <div className="md:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-2">
                Avatar URL
              </label>
              <input
                type="url"
                value={editForm?.avatar || ''}
                onChange={(e) => handleInputChange('avatar', e.target.value)}
                placeholder="https://example.com/avatar.jpg"
                className="input-field"
              />
            </div>
          </div>
        </div>
      )}

      {/* Stats */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="card text-center">
          <MessageSquare className="w-8 h-8 text-blue-500 mx-auto mb-2" />
          <p className="text-2xl font-bold text-gray-900">{userCreatedRooms?.length || 0}</p>
          <p className="text-sm text-gray-600">Rooms Created</p>
        </div>

        <div className="card text-center">
          <Globe className="w-8 h-8 text-green-500 mx-auto mb-2" />
          <p className="text-2xl font-bold text-gray-900">{allRooms?.length || 0}</p>
          <p className="text-sm text-gray-600">Total Rooms</p>
        </div>

        <div className="card text-center">
          <Crown className="w-8 h-8 text-yellow-500 mx-auto mb-2" />
          <p className="text-2xl font-bold text-gray-900">{blockchainNFTs?.length || 0}</p>
          <p className="text-sm text-gray-600">NFTs Owned</p>
        </div>

        <div className="card text-center">
          <User className="w-8 h-8 text-purple-500 mx-auto mb-2" />
          <p className="text-2xl font-bold text-gray-900">{userJoinedRooms?.length || 0}</p>
          <p className="text-sm text-gray-600">Available Rooms</p>
        </div>
      </div>

      {/* Created Rooms */}
      <div className="card">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-lg font-semibold text-gray-900">
            Rooms You Created ({userCreatedRooms?.length || 0})
          </h2>
          <Link to="/dashboard" className="btn-primary">
            Create New Room
          </Link>
        </div>

        {(userCreatedRooms?.length || 0) === 0 ? (
          <div className="text-center py-8">
            <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-3">
              <MessageSquare className="w-6 h-6 text-gray-400" />
            </div>
            <p className="text-gray-600">You haven't created any rooms yet.</p>
            <p className="text-sm text-gray-500 mt-1">Create your first room to start chatting!</p>
          </div>
        ) : (
          <div className="space-y-3">
            {(userCreatedRooms || []).map((room) => (
              <div
                key={room?.id || Math.random()}
                className="flex items-center justify-between p-4 bg-blue-50 rounded-lg border border-blue-200"
              >
                <div className="flex items-center space-x-3">
                  <div className="w-8 h-8 bg-primary-100 rounded-lg flex items-center justify-center">
                    <MessageSquare className="w-4 h-4 text-primary-600" />
                  </div>
                  <div>
                    <div className="flex items-center space-x-2">
                      <h3 className="font-medium text-gray-900">{room?.name || 'Unnamed Room'}</h3>
                      {room?.isPrivate ? (
                        <span className="text-xs bg-orange-100 text-orange-700 px-2 py-1 rounded flex items-center space-x-1">
                          <Lock className="w-3 h-3" />
                          <span>Private</span>
                        </span>
                      ) : (
                        <span className="text-xs bg-green-100 text-green-700 px-2 py-1 rounded flex items-center space-x-1">
                          <Globe className="w-3 h-3" />
                          <span>Public</span>
                        </span>
                      )}
                      <span className="text-xs bg-blue-100 text-blue-700 px-2 py-1 rounded-full">Creator</span>
                    </div>
                    <p className="text-sm text-gray-500">
                      Created {formatDate(room?.createdAt)} • Room #{room?.id}
                    </p>
                  </div>
                </div>
                <Link
                  to={`/room/${room?.id}`}
                  className="btn-secondary"
                >
                  Enter Room
                </Link>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Available Rooms */}
      <div className="card">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-lg font-semibold text-gray-900">
            Available Rooms ({userJoinedRooms?.length || 0})
          </h2>
        </div>

        {(userJoinedRooms?.length || 0) === 0 ? (
          <div className="text-center py-8">
            <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-3">
              <MessageSquare className="w-6 h-6 text-gray-400" />
            </div>
            <p className="text-gray-600">No other rooms available.</p>
            <p className="text-sm text-gray-500 mt-1">Check back later for new rooms!</p>
          </div>
        ) : (
          <div className="space-y-3">
            {(userJoinedRooms || []).slice(0, 5).map((room) => (
              <div
                key={room?.id || Math.random()}
                className="flex items-center justify-between p-4 bg-gray-50 rounded-lg"
              >
                <div className="flex items-center space-x-3">
                  <div className="w-8 h-8 bg-gray-100 rounded-lg flex items-center justify-center">
                    <MessageSquare className="w-4 h-4 text-gray-600" />
                  </div>
                  <div>
                    <div className="flex items-center space-x-2">
                      <h3 className="font-medium text-gray-900">{room?.name || 'Unnamed Room'}</h3>
                      {room?.isPrivate ? (
                        <span className="text-xs bg-orange-100 text-orange-700 px-2 py-1 rounded flex items-center space-x-1">
                          <Lock className="w-3 h-3" />
                          <span>Private</span>
                        </span>
                      ) : (
                        <span className="text-xs bg-green-100 text-green-700 px-2 py-1 rounded flex items-center space-x-1">
                          <Globe className="w-3 h-3" />
                          <span>Public</span>
                        </span>
                      )}
                    </div>
                    <p className="text-sm text-gray-500">
                      By {formatAddress(room?.creator)} • Room #{room?.id}
                    </p>
                  </div>
                </div>
                <Link
                  to={`/room/${room?.id}`}
                  className="btn-secondary"
                >
                  View Room
                </Link>
              </div>
            ))}
            {(userJoinedRooms?.length || 0) > 5 && (
              <div className="text-center pt-4">
                <Link to="/dashboard" className="text-primary-600 hover:text-primary-700 text-sm font-medium">
                  View all {userJoinedRooms.length} rooms →
                </Link>
              </div>
            )}
          </div>
        )}
      </div>

      {/* NFTs Section */}
      <div className="card">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-lg font-semibold text-gray-900">
            NFT Collection ({blockchainNFTs?.length || 0})
          </h2>
          <Link to="/nft" className="btn-primary">
            View NFT Marketplace
          </Link>
        </div>

        {(blockchainNFTs?.length || 0) === 0 ? (
          <div className="text-center py-8">
            <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-3">
              <ImageIcon className="w-6 h-6 text-gray-400" />
            </div>
            <p className="text-gray-600">You don't own any NFTs yet.</p>
            <p className="text-sm text-gray-500 mt-1">Visit the marketplace to mint or buy NFTs!</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
            {(blockchainNFTs || []).slice(0, 6).map((nft) => (
              <div key={nft?.tokenId || Math.random()} className="border border-gray-200 rounded-lg p-4 hover:shadow-md transition-shadow">
                <div className="w-full h-32 bg-gradient-to-br from-purple-400 to-pink-500 rounded-lg mb-3 flex items-center justify-center">
                  <ImageIcon className="w-8 h-8 text-white opacity-50" />
                </div>
                <h3 className="font-medium text-gray-900 mb-1">
                  {nft?.name || `NFT #${nft?.tokenId}`}
                </h3>
                <p className="text-sm text-gray-500 mb-2">Token ID: #{nft?.tokenId}</p>
                {nft?.isListed && (
                  <span className="text-xs bg-green-100 text-green-700 px-2 py-1 rounded inline-block">
                    Listed for Sale
                  </span>
                )}
              </div>
            ))}
          </div>
        )}
      </div>

      {/* QR Code Modal */}
      <QRCodeModal
        isOpen={showQRCode}
        onClose={() => setShowQRCode(false)}
        userInfo={{
          walletAddress,
          displayName: userProfile?.displayName,
          avatar: userProfile?.avatar
        }}
      />

      {/* QR Scanner Modal */}
      <QRScanner
        isOpen={showQRScanner}
        onClose={() => setShowQRScanner(false)}
        onFriendRequest={handleFriendRequest}
      />
    </div>
  );
};

export default Profile;
